#include<iostream>
#include<cmath>
using namespace std;
int n;
int t[100005];
struct node{
	int num;
	int data;
}f[100005];
int main(){
	cin>>n;
	int k;
	for(int i=1;i<=n;i++){
		cin>>k;
		t[k]++;
	}
	long long ans=0;
	int j=1;
	for(int i=1;i<=100000;i++){
		if(t[i]){
			f[j].data=i;
			f[j].num=t[i];
			j++;
		}
	}
	for(int i=2;i<=j;i++){
		ans+=max(f[i-1].num-f[i].num,0);
	}
	cout<<ans;
	return 0;
}
